1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PRICE = 60;
19	
20	const COMPONENT_TYPES = ["rune", "moonstone"];
21	
22	const isComponent = (item: { type: string }): boolean =>
23	  COMPONENT_TYPES.includes(item.type);
24	
25	const basePremiumFor = (item: { type: string }): number => BASE_PREMIUM[item.type];
26	
27	const itemPremium = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
28	  const base = basePremiumFor(item);
29	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
30	  const highEnchantmentSurcharge = item.enchantment !== undefined && item.enchantment >= 5 ? base * 0.3 : 0;
31	  return base + curseSurcharge + highEnchantmentSurcharge;
32	};
33	
34	const componentGroupPremium = (type: string, count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUM[type];
36	
37	export function quote(items: { type: string; cursed?: boolean; enchantment?: number }[], context: QuoteContext): number {
38	  const componentBasePremium = COMPONENT_TYPES.reduce((sum, type) => {
39	    const count = items.filter((item) => item.type === type).length;
40	    return sum + componentGroupPremium(type, count);
41	  }, 0);
42	
43	  const mainItemsPremium = items
44	    .filter((item) => !isComponent(item))
45	    .reduce((sum, item) => sum + itemPremium(item), 0);
46	
47	  return mainItemsPremium + componentBasePremium + POLICY_FEE;
48	}
49	
50	export function claim(): unknown {
51	  return undefined;
52	}
